# This script generates a secure pip.conf file for development environments

import os
import stat
import configparser
from pathlib import Path
from urllib.parse import urlparse


def validate_url(url: str) -> bool:
    """Validate that a URL uses HTTPS and has a valid structure."""
    try:
        parsed = urlparse(url)
        if parsed.scheme != "https":
            raise ValueError(
                f"URL must use HTTPS scheme, got '{parsed.scheme}': {url}"
            )
        if not parsed.hostname:
            raise ValueError(f"URL must have a valid hostname: {url}")
        # Reject URLs with embedded credentials
        if parsed.username or parsed.password:
            raise ValueError(
                "URLs must not contain embedded credentials. "
                "Use keyring or environment variables for authentication."
            )
        return True
    except ValueError:
        raise


def validate_hostname(hostname: str) -> bool:
    """Validate hostname format (basic validation)."""
    if not hostname or not isinstance(hostname, str):
        raise ValueError("Hostname must be a non-empty string.")
    # Basic hostname validation
    allowed_chars = set(
        "abcdefghijklmnopqrstuvwxyz"
        "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
        "0123456789.-"
    )
    if not all(c in allowed_chars for c in hostname):
        raise ValueError(f"Hostname contains invalid characters: {hostname}")
    if hostname.startswith("-") or hostname.startswith("."):
        raise ValueError(f"Hostname has invalid format: {hostname}")
    if ".." in hostname:
        raise ValueError(f"Hostname has invalid format: {hostname}")
    return True


def generate_pip_config(
    index_url: str,
    extra_index_urls: list[str] | None = None,
    trusted_hosts: list[str] | None = None,
    require_hashes: bool = True,
    timeout: int = 60,
    retries: int = 3,
    cache_dir: str | None = None,
    no_binary: list[str] | None = None,
) -> str:
    """
    Generate a secure pip.conf configuration.

    Args:
        index_url: Primary PyPI mirror URL (must be HTTPS).
        extra_index_urls: Additional index URLs (must be HTTPS).
        trusted_hosts: Hosts to trust for TLS (use sparingly; only for
                       internal hosts with valid but private CA certs).
        require_hashes: Whether to require hashes for reproducible installs.
        timeout: Connection timeout in seconds.
        retries: Number of retries for failed downloads.
        cache_dir: Custom cache directory path.
        no_binary: List of packages to never install as binary wheels.

    Returns:
        String content of the pip.conf file.
    """
    # Validate primary index URL - MUST be HTTPS
    validate_url(index_url)

    # Validate extra index URLs
    validated_extra_urls = []
    if extra_index_urls:
        for url in extra_index_urls:
            validate_url(url)
            validated_extra_urls.append(url)

    # Validate trusted hosts (should be used minimally)
    validated_trusted_hosts = []
    if trusted_hosts:
        for host in trusted_hosts:
            validate_hostname(host)
            validated_trusted_hosts.append(host)

    # Validate numeric parameters
    if not isinstance(timeout, int) or timeout < 1 or timeout > 300:
        raise ValueError("Timeout must be an integer between 1 and 300.")
    if not isinstance(retries, int) or retries < 0 or retries > 10:
        raise ValueError("Retries must be an integer between 0 and 10.")

    config = configparser.ConfigParser()

    # [global] section
    global_settings = {
        "index-url": index_url,
        "timeout": str(timeout),
        "retries": str(retries),
        # Require TLS/SSL for all connections
        # pip doesn't have a direct "require-ssl" but using HTTPS URLs enforces it
    }

    if validated_extra_urls:
        global_settings["extra-index-url"] = "\n    ".join(validated_extra_urls)

    if validated_trusted_hosts:
        # NOTE: trusted-host bypasses TLS verification.
        # Only use for internal mirrors with private CA certificates.
        # Prefer configuring the system CA bundle instead.
        global_settings["trusted-host"] = "\n    ".join(validated_trusted_hosts)

    if cache_dir:
        # Validate cache dir path (no path traversal)
        cache_path = Path(cache_dir).resolve()
        global_settings["cache-dir"] = str(cache_path)

    if require_hashes:
        global_settings["require-hashes"] = "true"

    if no_binary:
        for pkg in no_binary:
            if not pkg.replace("-", "").replace("_", "").isalnum() and pkg != ":all:":
                raise ValueError(f"Invalid package name in no_binary: {pkg}")
        global_settings["no-binary"] = ",".join(no_binary)

    config["global"] = global_settings

    # [install] section - secure defaults
    install_settings = {
        # Compile bytecode for installed packages
        "compile": "true",
        # Warn about insecure transport
        "progress-bar": "on",
    }
    config["install"] = install_settings

    # Generate the config string with security header comments
    lines = []
    lines.append("# pip configuration file - Generated securely")
    lines.append("# WARNING: Do not store credentials in this file.")
    lines.append("# Use keyring, environment variables, or netrc for authentication.")
    lines.append("# See: https://pip.pypa.io/en/stable/topics/authentication/")
    lines.append("#")
    lines.append("# All index URLs MUST use HTTPS to prevent MITM attacks.")
    lines.append("# trusted-host should only be used for internal mirrors with private CAs.")
    lines.append("# Prefer adding the private CA to the system trust store instead.")
    lines.append("")

    # Write config sections
    from io import StringIO
    output = StringIO()
    config.write(output)
    config_content = output.getvalue()

    return "\n".join(lines) + config_content


def write_pip_config(
    config_content: str,
    config_path: str | None = None,
    user_level: bool = True,
) -> Path:
    """
    Write pip configuration to disk with secure file permissions.

    Args:
        config_content: The pip.conf content string.
        config_path: Explicit path to write to. If None, uses default location.
        user_level: If True, write to user-level config; otherwise site-level.

    Returns:
        Path to the written configuration file.
    """
    if config_path:
        target_path = Path(config_path).resolve()
    elif user_level:
        # User-level pip config
        if os.name == "nt":
            # Windows: %APPDATA%\pip\pip.ini
            appdata = os.environ.get("APPDATA")
            if not appdata:
                raise EnvironmentError("APPDATA environment variable not set.")
            target_path = Path(appdata) / "pip" / "pip.ini"
        else:
            # Unix: ~/.config/pip/pip.conf (XDG compliant)
            xdg_config = os.environ.get(
                "XDG_CONFIG_HOME", str(Path.home() / ".config")
            )
            target_path = Path(xdg_config) / "pip" / "pip.conf"
    else:
        raise ValueError(
            "Site-level configuration requires explicit config_path for safety."
        )

    # Ensure parent directory exists with secure permissions
    target_path.parent.mkdir(parents=True, exist_ok=True)

    if os.name != "nt":
        # Set directory permissions to owner-only (700)
        os.chmod(target_path.parent, stat.S_IRWXU)

    # Write the file securely
    # Use os.open with explicit permissions to avoid race conditions
    if os.name != "nt":
        fd = os.open(
            str(target_path),
            os.O_WRONLY | os.O_CREAT | os.O_TRUNC,
            stat.S_IRUSR | stat.S_IWUSR,  # 600 - owner read/write only
        )
        try:
            os.write(fd, config_content.encode("utf-8"))
        finally:
            os.close(fd)
    else:
        # On Windows, use standard write (Windows ACLs handle permissions differently)
        target_path.write_text(config_content, encoding="utf-8")

    print(f"pip configuration written to: {target_path}")
    print(f"File permissions: owner read/write only")

    return target_path


