def create_development_config(
    internal_mirror_url: str = "https://pypi.internal.example.com/simple/",
    fallback_to_public: bool = True,
    output_path: str | None = None,
) -> Path:
    """
    Create a complete development environment pip configuration.

    Args:
        internal_mirror_url: URL of the internal PyPI mirror (HTTPS required).
        fallback_to_public: Whether to include public PyPI as a fallback.
        output_path: Optional explicit output path.

    Returns:
        Path to the generated config file.
    """
    extra_urls = []
    trusted_hosts = []

    if fallback_to_public:
        extra_urls.append("https://pypi.org/simple/")

    # Parse the internal mirror hostname for trusted-host
    # Only add to trusted-host if using a private CA
    # (In production, prefer adding the CA to the system trust store)
    parsed_mirror = urlparse(internal_mirror_url)
    if parsed_mirror.hostname and not parsed_mirror.hostname.endswith("pypi.org"):
        # For internal mirrors that may use private CA certificates
        trusted_hosts.append(parsed_mirror.hostname)

    config_content = generate_pip_config(
        index_url=internal_mirror_url,
        extra_index_urls=extra_urls if extra_urls else None,
        trusted_hosts=trusted_hosts if trusted_hosts else None,
        require_hashes=False,  # Set True for production/CI for reproducibility
        timeout=60,
        retries=3,
        cache_dir=None,  # Use default cache directory
    )

    config_path = write_pip_config(
        config_content=config_content,
        config_path=output_path,
        user_level=(output_path is None),
    )

    return config_path


